<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Fut</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> Future</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">Output</span><span style="color:#94E2D5;"> =</span><span style="color:#F9E2AF;font-style:italic;"> ToolResult</span><span style="color:#89DCEB;">&gt;</span><span style="color:#94E2D5;"> +</span><span style="color:#F9E2AF;font-style:italic;"> Send</span><span style="color:#94E2D5;"> +</span><span style="color:#9399B2;"> &#39;</span><span style="color:#89B4FA;font-style:italic;">static</span><span style="color:#9399B2;">,</span></span>
