<span class="line"><span style="color:#F38BA8;">                        self</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">tools</span><span style="color:#9399B2;">[</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">definition</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">name</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">owner</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">clone</span><span style="color:#9399B2;">(),</span></span>
