<span class="line"><span style="color:#F9E2AF;font-style:italic;">    Ok</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;">serde_json</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">result</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap_or_default</span><span style="color:#9399B2;">())</span></span>
